const { ApolloServer, gql, AuthenticationError, ForbiddenError } = require('apollo-server');
const { GraphQLError } = require('graphql');

// Mock database
const invoices = [
  { id: '1', userId: 'user1', amount: 100, description: 'Invoice 1', status: 'paid' },
  { id: '2', userId: 'user2', amount: 200, description: 'Invoice 2', status: 'pending' },
  { id: '3', userId: 'user1', amount: 300, description: 'Invoice 3', status: 'paid' },
  { id: '4', userId: 'user3', amount: 400, description: 'Invoice 4', status: 'pending' },
];

const users = [
  { id: 'user1', name: 'Alice', email: 'alice@example.com' },
  { id: 'user2', name: 'Bob', email: 'bob@example.com' },
  { id: 'user3', name: 'Charlie', email: 'charlie@example.com' },
];

const typeDefs = gql`
  type Invoice {
    id: ID!
    userId: ID!
    amount: Float!
    description: String!
    status: String!
  }

  type Query {
    invoice(id: ID!): Invoice
    myInvoices: [Invoice!]!
  }
`;

const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      if (!context.user) {
        throw new AuthenticationError('You must be logged in to view invoices');
      }

      const invoice = invoices.find(inv => inv.id === id);
      
      if (!invoice) {
        throw new GraphQLError('Invoice not found', {
          extensions: { code: 'NOT_FOUND' }
        });
      }

      // Authorization check: ensure user can only access their own invoices
      if (invoice.userId !== context.user.id) {
        throw new ForbiddenError('You do not have permission to view this invoice');
      }

      return invoice;
    },

    myInvoices: (parent, args, context) => {
      if (!context.user) {
        throw new AuthenticationError('You must be logged in to view invoices');
      }

      // Return only invoices belonging to the authenticated user
      return invoices.filter(invoice => invoice.userId === context.user.id);
    }
  }
};

// Mock authentication middleware (already implemented as per requirements)
const getUser = (token) => {
  if (token === 'user1-token') return { id: 'user1', name: 'Alice' };
  if (token === 'user2-token') return { id: 'user2', name: 'Bob' };
  if (token === 'user3-token') return { id: 'user3', name: 'Charlie' };
  return null;
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    const token = req.headers.authorization || '';
    const user = getUser(token);
    return { user };
  },
  introspection: process.env.NODE_ENV !== 'production',
  playground: process.env.NODE_ENV !== 'production',
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`Server ready at ${url}`);
});

module.exports = { typeDefs, resolvers, server };